import{f as d,D as E,o as r,c as u,a2 as e,b as s,w as o,a as n,G as i,a5 as l}from"./chunks/framework.DHYrF-q6.js";const T=JSON.parse('{"title":"监控告警体系","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/monitoring-alerting/index.md","filePath":"high-concurrency/monitoring-alerting/index.md","lastUpdated":1780917874000}'),c={name:"high-concurrency/monitoring-alerting/index.md"};function A(g,t,q,h,p,B){const a=E("Mermaid");return r(),u("div",null,[t[2]||(t[2]=e('<h1 id="监控告警体系" tabindex="-1">监控告警体系 <a class="header-anchor" href="#监控告警体系" aria-label="Permalink to &quot;监控告警体系&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>监控告警是高并发系统的&quot;眼睛&quot;和&quot;耳朵&quot;——没有监控，系统就是黑盒运行；没有告警，故障发生了都不知道。本模块覆盖从指标体系设计到告警规则配置的完整方法论。</p><div class="tip custom-block"><p class="custom-block-title">核心思路</p><p>监控不是&quot;装个 Prometheus + Grafana 就完事了&quot;，而是<strong>指标定义 → 采集 → 存储 → 可视化 → 告警 → 响应</strong>的完整工程体系。</p></div><div class="warning custom-block"><p class="custom-block-title">面试重点</p><p>高级工程师面试中，监控相关的问题往往考察&quot;你如何发现和定位线上问题&quot;，而非&quot;你用过什么监控工具&quot;。</p></div><h2 id="可观测性三大支柱" tabindex="-1">可观测性三大支柱 <a class="header-anchor" href="#可观测性三大支柱" aria-label="Permalink to &quot;可观测性三大支柱&quot;">​</a></h2>',6)),(r(),s(l,null,{default:o(()=>[i(a,{id:"mermaid-22",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20O%5B%22%E5%8F%AF%E8%A7%82%E6%B5%8B%E6%80%A7%20Observability%22%5D%20--%3E%20M%5B%22Metrics%3Cbr%2F%3E%E6%8C%87%E6%A0%87%22%5D%0A%20%20%20%20O%20--%3E%20L%5B%22Logs%3Cbr%2F%3E%E6%97%A5%E5%BF%97%22%5D%0A%20%20%20%20O%20--%3E%20T%5B%22Traces%3Cbr%2F%3E%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA%22%5D%0A%20%20%20%20%0A%20%20%20%20M%20--%3E%20M1%5B%22%E8%81%9A%E5%90%88%E6%95%B0%E6%8D%AE%EF%BC%9AQPS%E3%80%81RT%E3%80%81%E9%94%99%E8%AF%AF%E7%8E%87%22%5D%0A%20%20%20%20M%20--%3E%20M2%5B%22%E6%97%B6%E5%BA%8F%E6%95%B0%E6%8D%AE%EF%BC%9ACPU%E3%80%81%E5%86%85%E5%AD%98%E3%80%81GC%22%5D%0A%20%20%20%20M%20--%3E%20M3%5B%22%E5%AD%98%E5%82%A8%EF%BC%9APrometheus%20TSDB%22%5D%0A%20%20%20%20%0A%20%20%20%20L%20--%3E%20L1%5B%22%E7%A6%BB%E6%95%A3%E4%BA%8B%E4%BB%B6%EF%BC%9A%E8%AF%B7%E6%B1%82%E6%97%A5%E5%BF%97%E3%80%81%E9%94%99%E8%AF%AF%E5%A0%86%E6%A0%88%22%5D%0A%20%20%20%20L%20--%3E%20L2%5B%22%E5%85%A8%E6%96%87%E6%A3%80%E7%B4%A2%EF%BC%9AELK%20%2F%20Loki%22%5D%0A%20%20%20%20L%20--%3E%20L3%5B%22%E4%B8%8A%E4%B8%8B%E6%96%87%EF%BC%9AtraceId%E3%80%81userId%22%5D%0A%20%20%20%20%0A%20%20%20%20T%20--%3E%20T1%5B%22%E8%AF%B7%E6%B1%82%E9%93%BE%E8%B7%AF%EF%BC%9A%E8%B7%A8%E6%9C%8D%E5%8A%A1%E8%B0%83%E7%94%A8%E9%93%BE%22%5D%0A%20%20%20%20T%20--%3E%20T2%5B%22%E7%93%B6%E9%A2%88%E5%AE%9A%E4%BD%8D%EF%BC%9A%E5%93%AA%E4%B8%AA%E6%9C%8D%E5%8A%A1%E6%85%A2%22%5D%0A%20%20%20%20T%20--%3E%20T3%5B%22%E6%A0%87%E5%87%86%EF%BC%9AOpenTelemetry%22%5D%0A%20%20%20%20%0A%20%20%20%20style%20O%20fill%3A%23fef2f2%2Cstroke%3A%23dc2626%2Ccolor%3A%23991b1b%0A%20%20%20%20style%20M%20fill%3A%23dbeafe%2Cstroke%3A%232563eb%2Ccolor%3A%231e40af%0A%20%20%20%20style%20L%20fill%3A%23dcfce7%2Cstroke%3A%2316a34a%2Ccolor%3A%23166534%0A%20%20%20%20style%20T%20fill%3A%23fef3c7%2Cstroke%3A%23d97706%2Ccolor%3A%2392400e%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e('<table tabindex="0"><thead><tr><th>支柱</th><th>解决的问题</th><th>典型工具</th><th>数据特点</th></tr></thead><tbody><tr><td><strong>Metrics</strong></td><td>系统现在健康吗？</td><td>Prometheus + Grafana</td><td>聚合时序数据，低存储成本</td></tr><tr><td><strong>Logs</strong></td><td>发生了什么？</td><td>ELK / Loki</td><td>离散事件，全量上下文</td></tr><tr><td><strong>Traces</strong></td><td>请求经过了哪些服务？</td><td>Jaeger / SkyWalking</td><td>链路调用关系</td></tr></tbody></table><h2 id="监控体系分层" tabindex="-1">监控体系分层 <a class="header-anchor" href="#监控体系分层" aria-label="Permalink to &quot;监控体系分层&quot;">​</a></h2>',2)),(r(),s(l,null,{default:o(()=>[i(a,{id:"mermaid-88",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20L1%5B%22%E4%B8%9A%E5%8A%A1%E7%9B%91%E6%8E%A7%3Cbr%2F%3E%E8%AE%A2%E5%8D%95%E9%87%8F%2F%E6%94%AF%E4%BB%98%E6%88%90%E5%8A%9F%E7%8E%87%2FDAU%22%5D%20--%3E%20L2%5B%22%E5%BA%94%E7%94%A8%E7%9B%91%E6%8E%A7%3Cbr%2F%3EQPS%2FRT%2F%E9%94%99%E8%AF%AF%E7%8E%87%2FJVM%22%5D%0A%20%20%20%20L2%20--%3E%20L3%5B%22%E4%B8%AD%E9%97%B4%E4%BB%B6%E7%9B%91%E6%8E%A7%3Cbr%2F%3EMySQL%2FRedis%2FMQ%22%5D%0A%20%20%20%20L3%20--%3E%20L4%5B%22%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%E7%9B%91%E6%8E%A7%3Cbr%2F%3ECPU%2F%E5%86%85%E5%AD%98%2F%E7%A3%81%E7%9B%98%2F%E7%BD%91%E7%BB%9C%22%5D%0A%20%20%20%20%0A%20%20%20%20style%20L1%20fill%3A%23fce7f3%2Cstroke%3A%23db2777%2Ccolor%3A%239d174d%0A%20%20%20%20style%20L2%20fill%3A%23fef3c7%2Cstroke%3A%23d97706%2Ccolor%3A%2392400e%0A%20%20%20%20style%20L3%20fill%3A%23dbeafe%2Cstroke%3A%232563eb%2Ccolor%3A%231e40af%0A%20%20%20%20style%20L4%20fill%3A%23dcfce7%2Cstroke%3A%2316a34a%2Ccolor%3A%23166534%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[n(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e(`<h2 id="黄金监控指标" tabindex="-1">黄金监控指标 <a class="header-anchor" href="#黄金监控指标" aria-label="Permalink to &quot;黄金监控指标&quot;">​</a></h2><h3 id="四大黄金指标-google-sre" tabindex="-1">四大黄金指标（Google SRE） <a class="header-anchor" href="#四大黄金指标-google-sre" aria-label="Permalink to &quot;四大黄金指标（Google SRE）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>含义</th><th>高并发场景关注点</th></tr></thead><tbody><tr><td><strong>延迟 Latency</strong></td><td>请求处理时间</td><td>P99/P999 长尾延迟</td></tr><tr><td><strong>流量 Traffic</strong></td><td>系统负载量</td><td>QPS/TPS、并发连接数</td></tr><tr><td><strong>错误 Errors</strong></td><td>失败请求比例</td><td>错误率、错误码分布</td></tr><tr><td><strong>饱和度 Saturation</strong></td><td>资源使用程度</td><td>连接池、线程池、队列长度</td></tr></tbody></table><h3 id="red-方法论-适用于微服务" tabindex="-1">RED 方法论（适用于微服务） <a class="header-anchor" href="#red-方法论-适用于微服务" aria-label="Permalink to &quot;RED 方法论（适用于微服务）&quot;">​</a></h3><ul><li><strong>Rate</strong>：每秒请求数</li><li><strong>Errors</strong>：错误请求比例</li><li><strong>Duration</strong>：请求耗时分布</li></ul><h3 id="use-方法论-适用于资源" tabindex="-1">USE 方法论（适用于资源） <a class="header-anchor" href="#use-方法论-适用于资源" aria-label="Permalink to &quot;USE 方法论（适用于资源）&quot;">​</a></h3><ul><li><strong>Utilization</strong>：资源利用率（如 CPU 使用率）</li><li><strong>Saturation</strong>：资源饱和度（如队列长度）</li><li><strong>Errors</strong>：资源错误数（如磁盘 IO 错误）</li></ul><h2 id="监控数据流" tabindex="-1">监控数据流 <a class="header-anchor" href="#监控数据流" aria-label="Permalink to &quot;监控数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用(Micrometer) → Prometheus(Pull) → TSDB 存储 → Grafana 可视化</span></span>
<span class="line"><span>                                              ↓</span></span>
<span class="line"><span>                                     AlertManager → 告警通知</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><ol><li><strong>指标采集与 Prometheus</strong>：理解 Prometheus Pull 模型、Metrics 类型、PromQL 查询</li><li><strong>告警体系设计</strong>：掌握告警分级、降噪、路由、响应流程</li></ol><hr><h2 id="面试题" tabindex="-1">面试题 <a class="header-anchor" href="#面试题" aria-label="Permalink to &quot;面试题&quot;">​</a></h2><h3 id="_1-可观测性三大支柱的关系是什么" tabindex="-1">1. 可观测性三大支柱的关系是什么？ <a class="header-anchor" href="#_1-可观测性三大支柱的关系是什么" aria-label="Permalink to &quot;1. 可观测性三大支柱的关系是什么？&quot;">​</a></h3><p><strong>知识要点</strong>：Metrics、Logs、Traces 三者互补，通过 traceId 串联形成完整的故障排查链路。Metrics 告诉你&quot;有异常&quot;（如 QPS 突然下降 50%），Traces 定位&quot;哪个环节异常&quot;（如支付服务的调用在 200ms 超时），Logs 提供&quot;原因是什么&quot;（如 NullPointerException 堆栈）。</p><p><strong>项目场景</strong>：我们当时的监控体系用了 Prometheus（Metrics）+ ELK（Logs）+ SkyWalking（Traces）三件套。线上 300 个微服务节点，日均产生 20TB 日志。没有这三个支柱的联动之前，每次故障排查平均耗时 45 分钟——先看 Grafana 大盘找异常服务，再登录服务器 grep 日志，最后靠经验猜测调用链。</p><p><strong>踩坑经历</strong>：三大支柱联动的关键是 traceId 的生成和透传。我们第一次上线时，网关生成 traceId 并放到 HTTP Response Header 返回给前端，但前端没有把 traceId 带到下一次请求中——导致用户报错时我们拿不到 traceId，只能根据&quot;用户 ID + 时间戳&quot;在 ELK 里大海捞针。后来改为：前端每次请求把上一次 Response 中的 traceId 放到 Request Header <code>X-Trace-Id</code>，网关如果收到就沿用，没收到则新建。第二个坑：SkyWalking 的 Trace 上报是异步批量发送的，高峰期有 30 秒延迟——故障刚发生时 Trace 还没到 SkyWalking，只能先看 Metrics 和 Logs。</p><p><strong>量化结果</strong>：三支柱联动完善后，故障平均定位时间从 45 分钟降到 8 分钟。监控覆盖率从 60%（只覆盖了应用层）提升到 95%（覆盖到中间件和基础设施层）。</p><p><strong>面试官追问</strong>：</p><ul><li>&quot;如果 Metrics 告警了但 Traces 里没看到异常，可能是什么原因？&quot; → 三种可能：(1) Metrics 阈值设太敏感（瞬时波动触发告警但实际没问题）；(2) Traces 采样率太低（如采样 10%，异常请求刚好没被采到）；(3) 基础设施层的问题（如磁盘 IO 慢、网络丢包）不会体现在 Traces 的 Span 里，但 Metrics 的 CPU/Disk 指标会暴露。所以 Metrics 和 Traces 不是一一对应的。</li><li>&quot;小公司资源有限，三大支柱怎么取舍？&quot; → 优先级：Metrics &gt; Logs &gt; Traces。先上 Prometheus + Grafana（最便宜，300 元/月的云服务器就能跑），再上 ELK（日志集中存储，成本中等），最后有钱了上 SkyWalking/Jaeger（链路追踪，存储成本最高）。如果只能选一个，选 Metrics——至少系统挂了你能知道。</li></ul><hr><h3 id="_2-四大黄金指标分别关注什么" tabindex="-1">2. 四大黄金指标分别关注什么？ <a class="header-anchor" href="#_2-四大黄金指标分别关注什么" aria-label="Permalink to &quot;2. 四大黄金指标分别关注什么？&quot;">​</a></h3><p><strong>知识要点</strong>：Google SRE 的四大黄金指标——延迟（Latency）、流量（Traffic）、错误（Errors）、饱和度（Saturation）。延迟关注 P99/P999 长尾，流量关注 QPS/TPS 趋势，错误关注错误率（显式+隐式），饱和度关注资源瓶颈（CPU/内存/连接池/队列）。</p><p><strong>项目场景</strong>：我们当时为微服务集群建立标准化监控大盘，每个服务一个 Grafana Dashboard，统一展示四大黄金指标。但是 Dashboard 刚上线时，大家反映&quot;信息太多看不完&quot;。</p><p><strong>踩坑经历</strong>：四大黄金指标的关键不是&quot;四个都看&quot;，而是&quot;先看饱和度，再看错误率&quot;。我们最初把四个指标平铺展示，运维看了一眼觉得&quot;都挺正常的&quot;就跳过了——结果一个服务的线程池队列积压了 2000 个请求（饱和度异常），但 QPS 和 RT 还没暴露问题（因为请求还在排队，没到超时）。到超时那一瞬间错误率从 0% 跳到 30%，已经晚了。后来调整了 Dashboard 布局：饱和度（连接池/线程池/队列）放在最上面，下面才是 RT 和错误率。</p><p><strong>量化结果</strong>：Dashboard 布局调整后，故障的&quot;预警发现率&quot;从 20%（都是错误率飙升后才报警）提升到 65%（饱和度异常时就被发现并处理）。平均故障恢复时间（MTTR）从 25 分钟降到 12 分钟。</p><p><strong>面试官追问</strong>：</p><ul><li>&quot;隐式错误是什么？举个例子。&quot; → 隐式错误是返回了 HTTP 200 但内容不对——比如商品详情页返回了&quot;库存为空&quot;（HTTP 200），但实际上接口超时降级返回了默认空数据。如果只看 HTTP 状态码，错误率是 0%，但用户看到空白页。我们的做法是在业务代码中埋点&quot;降级次数&quot;、&quot;空数据返回次数&quot;作为隐式错误指标，这些也被计入四大黄金指标的 Errors。</li><li>&quot;饱和度的告警阈值怎么设？&quot; → 不是&quot;80% 就告警&quot;，要分资源类型——CPU 用 70%（留 30% 应对突发），内存用 85%（GC 需要空间），线程池队列用 50%（排队超过一半就说明处理能力不够了），数据库连接池用 70%。阈值定好之后还要观察 2 周看误报率，再微调。</li></ul><hr><h3 id="_3-red-和-use-分别适用什么场景" tabindex="-1">3. RED 和 USE 分别适用什么场景？ <a class="header-anchor" href="#_3-red-和-use-分别适用什么场景" aria-label="Permalink to &quot;3. RED 和 USE 分别适用什么场景？&quot;">​</a></h3><p><strong>知识要点</strong>：RED（Rate/Errors/Duration）适用于请求驱动型服务（如 HTTP API），关注每个 endpoint 的流量、错误率和延迟。USE（Utilization/Saturation/Errors）适用于资源型组件（如数据库、缓存、消息队列），关注资源利用率、饱和度、错误。</p><p><strong>项目场景</strong>：我们当时做监控标准化，要求所有 HTTP 服务使用 RED 指标（在 Spring Boot Actuator 中暴露 <code>/actuator/prometheus</code>），所有中间件使用 USE 指标（通过专用 Exporter 采集）。</p><p><strong>踩坑经历</strong>：我们尝试给 Redis 套用 RED 指标——统计 Redis 的 QPS、RT、错误率。结果 Redis 的 RT 非常稳定（0.5ms），即使内存使用率到 95% 时 RT 也没有明显变化——因为 Redis 的单线程模型在内存满之前性能不会下降，只是触发 maxmemory 淘汰策略。真正的瓶颈是&quot;内存使用率&quot;和&quot;连接数&quot;（USE 指标），但 RED 指标完全没反映出来。这个教训说明——选错方法论比没有方法论更危险。</p><p><strong>量化结果</strong>：中间件统一采用 USE 指标后，Redis 的内存使用率告警从&quot;无&quot;变为&quot;提前 30 分钟预警&quot;，避免了 3 次 Redis 内存打满导致的服务不可用。</p><p><strong>面试官追问</strong>：</p><ul><li>&quot;一个服务既是请求驱动型（对外提供 HTTP API），内部又依赖资源型组件（MySQL），怎么选方法论？&quot; → 双重覆盖——对外用 RED（关注 QPS/RT/错误率，面向业务），对内用 USE（关注连接池/内存/CPU，面向运维）。实际上大部分服务都需要同时看 RED 和 USE。</li><li>&quot;有没有比 RED/USE 更简单实用的方法？&quot; → 有——&quot;最重要三指标&quot;法：对于任何服务，只需回答三个问题——&quot;有没有在处理请求？&quot;（QPS）、&quot;处理得快不快？&quot;（P99 RT）、&quot;有没有出错？&quot;（错误率）。这三个指标覆盖了 80% 的监控需求，剩下的 20% 才需要更细粒度的 USE/RED。</li></ul><hr><h3 id="_4-监控体系分层怎么设计" tabindex="-1">4. 监控体系分层怎么设计？ <a class="header-anchor" href="#_4-监控体系分层怎么设计" aria-label="Permalink to &quot;4. 监控体系分层怎么设计？&quot;">​</a></h3><p><strong>知识要点</strong>：四层监控——基础设施层（CPU/内存/磁盘/网络）、中间件层（MySQL/Redis/MQ）、应用层（QPS/RT/错误率/JVM）、业务层（订单量/支付成功率/DAU）。四层之间通过 traceId 和 hostname 关联，从业务异常可以一直钻取到基础设施指标。</p><p><strong>项目场景</strong>：我们当时给一个电商系统搭建统一的监控平台，四层用了不同的工具——基础设施用 Node Exporter + Prometheus，中间件用各官方 Exporter（Redis Exporter/MySQL Exporter），应用层用 Micrometer + Actuator，业务层用自定义埋点 + InfluxDB。</p><p><strong>踩坑经历</strong>：四层监控最大的坑是&quot;信息孤岛&quot;——业务监控显示&quot;支付成功率下降 5%&quot;，但我无法从 Grafana 面板直接钻取到&quot;是哪个服务、哪台机器、哪个数据库出了问题&quot;。因为每一层监控用不同的工具和数据源，数据没有打通。后来我们强制规范化了所有监控数据的 Label（<code>service_name</code>、<code>hostname</code>、<code>datacenter</code>），在 Grafana 里做了联动跳转链接——点击业务层的异常统计数据，可以一键跳转到对应服务的应用层面板，再到中间件面板。</p><p><strong>量化结果</strong>：四层监控面板联动后，从&quot;发现业务异常&quot;到&quot;定位技术根因&quot;的时间从 20 分钟降到 5 分钟。监控告警的误报率从 35% 降到 12%（因为通过多层关联可以做告警降噪——&quot;业务层下降 + 应用层正常 = 可能是业务活动波动，不告警&quot;）。</p><p><strong>面试官追问</strong>：</p><ul><li>&quot;告警应该基于哪一层的指标？业务层异常才告警还是应用层异常就告警？&quot; → 告警优先级：业务层 &gt; 应用层 &gt; 中间件层 &gt; 基础设施层。业务层的&quot;支付成功率下降&quot;一定告警（P0），而&quot;某台机器 CPU 80%&quot;可能只是 P2（因为还有负载均衡分摊）。但要注意——如果应用层的&quot;错误率超过 5%&quot;但业务层还没反映出来（业务有降级兜底），也应该告警（P1），因为这说明降级正在生效，核心链路某个环节已经出了问题。</li><li>&quot;日志怎么和 Metrics 联动？&quot; → 在 Metrics 告警的通知中附带&quot;一键跳转 ELK&quot;的链接——链接中包含 service_name、时间范围、traceId（如果有）作为查询参数，点开就是过滤好的日志。这个体验优化把&quot;收到告警 → 看到日志&quot;的时间从 2 分钟（手动输入查询条件）降到 5 秒。</li></ul><hr><h3 id="_5-metrics-logs-traces-什么时候用哪个" tabindex="-1">5. Metrics / Logs / Traces 什么时候用哪个？ <a class="header-anchor" href="#_5-metrics-logs-traces-什么时候用哪个" aria-label="Permalink to &quot;5. Metrics / Logs / Traces 什么时候用哪个？&quot;">​</a></h3><p><strong>知识要点</strong>：日常巡检用 Metrics（聚合查询快），故障告警用 Metrics（可设阈值），故障定位用 Traces（看调用链），根因分析用 Logs（最详细上下文）。</p><p><strong>项目场景</strong>：我们当时的故障处理 SOP 规定了&quot;三阶段排查&quot;——第一阶段 3 分钟（看 Metrics 大盘和告警，确认故障范围和严重程度），第二阶段 5 分钟（看 Traces 调用链，定位到具体服务和接口），第三阶段不限（看 Logs，深入代码级别根因）。</p><p><strong>踩坑经历</strong>：有一次 Metrics 和 Traces 都显示&quot;库存服务正常&quot;，但 Logs 里有大量 <code>Duplicate entry for key &#39;PRIMARY&#39;</code> 错误——原因是业务方传了重复的订单 ID，库存服务拒绝处理（返回了错误码，但业务方没有重试，所以 Metrics 的错误率只有 0.1%，被忽略了）。最后是客服收到用户投诉才发现的——如果只看 Metrics 和 Traces，这个故障就被漏掉了。</p><p><strong>量化结果</strong>：三阶段排查 SOP 固化后，每次故障都能在规定时间内完成定位。SOP 配合自动化 runbook（预定义的排查命令），P1 故障的平均处理时间从 35 分钟降到 15 分钟。</p><p><strong>面试官追问</strong>：</p><ul><li>&quot;ELK 日志量太大，搜索很慢，有什么优化技巧？&quot; → (1) 日志分级——ERROR/WARN 单独索引（优先级高，保留 30 天），INFO/DEBUG 合并索引（优先级低，保留 7 天）；(2) 按服务名建索引（<code>logs-order-service-2026.06</code>），不要全量打到一个索引里；(3) 搜索时优先用&quot;短语匹配&quot;而非&quot;模糊搜索&quot;。我们优化后 ELK 搜索 RT 从 12 秒降到 1.5 秒。</li><li>&quot;Traces 的采样率应该设多少？&quot; → 正常流量采样 10%（够用了，成本可控），错误流量 100% 采样（关键故障不能漏），压测流量 100% 采样（排查瓶颈需要）。SkyWalking 和 Jaeger 都支持动态采样策略。 |</li></ul>`,52))])}const P=d(c,[["render",A]]);export{T as __pageData,P as default};
